import math

def _get_median_of_small_array(arr_part):
    arr_part.sort()
    return arr_part[len(arr_part) // 2]

def _partition_around_pivot(arr, low, high, pivot_value):
    pivot_idx = -1
    for i in range(low, high + 1):
        if arr[i] == pivot_value:
            pivot_idx = i
            break

    arr[pivot_idx], arr[high] = arr[high], arr[pivot_idx]

    i = low - 1
    for j in range(low, high):
        if arr[j] <= arr[high]:
            i += 1
            arr[i], arr[j] = arr[j], arr[i]

    arr[i+1], arr[high] = arr[high], arr[i+1]

    return i + 1

def _median_of_medians_recursive(arr, k, low, high):
    if high - low + 1 <= 5:
        sub_arr = arr[low : high + 1]
        sub_arr.sort()
        return sub_arr[k - low]

    medians = []
    for i in range(low, high + 1, 5):
        group_end = min(i + 4, high)
        group = arr[i : group_end + 1]
        medians.append(_get_median_of_small_array(group))

    pivot_value = _median_of_medians_recursive(medians, len(medians) // 2, 0, len(medians) - 1)

    pivot_final_idx = _partition_around_pivot(arr, low, high, pivot_value)

    if k == pivot_final_idx:
        return arr[k]
    elif k < pivot_final_idx:
        return _median_of_medians_recursive(arr, k, low, pivot_final_idx - 1)
    else:
        return _median_of_medians_recursive(arr, k, pivot_final_idx + 1, high)

def median_of_medians(arr, k):
    if not arr:
        raise ValueError("Input array cannot be empty.")
    if not (0 <= k < len(arr)):
        raise IndexError(f"k must be between 0 and {len(arr) - 1} for an array of size {len(arr)}.")

    arr_copy = list(arr) 

    return _median_of_medians_recursive(arr_copy, k, 0, len(arr_copy) - 1)
